import pyotp
import qrcode
import os
import time

class TOTPAuthenticator:
    def __init__(self):
        self.secrets = {}

    def generate_secret(self, user_identifier):
        secret = pyotp.random_base32()
        self.secrets[user_identifier] = secret
        return secret

    def generate_qr_code(self, user_identifier):
        secret = self.secrets[user_identifier]
        uri = pyotp.totp.TOTP(secret).provisioning_uri(name=user_identifier, issuer_name='MyMFAApp')
        qr = qrcode.make(uri)
        qr_path = f"{user_identifier}_qrcode.png"
        qr.save(qr_path)
        return qr_path

    def validate_totp(self, user_identifier, user_input):
        secret = self.secrets.get(user_identifier)
        if secret:
            totp = pyotp.TOTP(secret)
            return totp.verify(user_input)
        return False

if __name__ == "__main__":
    authenticator = TOTPAuthenticator()
    
